# Clean A* Pathfinding Implementation

After deobfuscating the code, I can see this is an **A* pathfinding algorithm** on a 2D grid with diagonal movement support. Here's a clean implementation:

```javascript
// Grid configuration
const GRID_WIDTH = 20;
const GRID_HEIGHT = 15;

const config = {
  heuristic: 'manhattan',
  diagonalCost: 1.414,
  straightCost: 1,
  maxIterations: 1000,
  wallProbability: 0.25
};

// Generate grid with random walls (1 = wall, 0 = open)
const grid = [];
for (let y = 0; y < GRID_HEIGHT; y++) {
  grid[y] = [];
  for (let x = 0; x < GRID_WIDTH; x++) {
    grid[y][x] = Math.random() < config.wallProbability ? 1 : 0;
  }
}

// Define start and end nodes
const startNode = { x: 0, y: 0 };
const endNode = { x: GRID_WIDTH - 1, y: GRID_HEIGHT - 1 };

// Ensure start and end are not walls
grid[startNode.y][startNode.x] = 0;
grid[endNode.y][endNode.x] = 0;

// Heuristic function: Manhattan or Euclidean distance
function heuristic(nodeA, nodeB) {
  const dx = Math.abs(nodeA.x - nodeB.x);
  const dy = Math.abs(nodeA.y - nodeB.y);

  if (config.heuristic === 'manhattan') {
    return dx + dy;
  }
  return Math.sqrt(dx * dx + dy * dy);
}

// Get traversable neighbors of a node
function getNeighbors(node) {
  const neighbors = [];
  const directions = [
    { dx:  0, dy: -1, cost: config.straightCost },  // up
    { dx:  0, dy:  1, cost: config.straightCost },  // down
    { dx: -1, dy:  0, cost: config.straightCost },  // left
    { dx:  1, dy:  0, cost: config.straightCost },  // right
    { dx: -1, dy: -1, cost: config.diagonalCost },  // up-left
    { dx:  1, dy: -1, cost: config.diagonalCost },  // up-right
    { dx: -1, dy:  1, cost: config.diagonalCost },  // down-left
    { dx:  1, dy:  1, cost: config.diagonalCost },  // down-right
  ];

  for (const dir of directions) {
    const nx = node.x + dir.dx;
    const ny = node.y + dir.dy;

    if (nx >= 0 && nx < GRID_WIDTH && ny >= 0 && ny < GRID_HEIGHT && grid[ny][nx] === 0) {
      neighbors.push({ x: nx, y: ny, moveCost: dir.cost });
    }
  }

  return neighbors;
}

// Create a unique string key for a node
function nodeKey(node) {
  return node.x + ',' + node.y;
}

// A* pathfinding algorithm
function findPath(start, end) {
  const startKey = nodeKey(start);

  const openSet = {};          // nodes to evaluate
  const closedSet = {};        // already evaluated nodes
  const cameFrom = {};         // parent tracking for path reconstruction
  const gScore = {};           // cost from start to node
  const fScore = {};           // gScore + heuristic estimate

  openSet[startKey] = start;
  gScore[startKey] = 0;
  fScore[startKey] = heuristic(start, end);

  let iterations = 0;

  while (Object.keys(openSet).length > 0 && iterations < config.maxIterations) {
    iterations++;

    // Find the node in openSet with lowest fScore
    let currentKey = null;
    let lowestF = Infinity;
    for (const key in openSet) {
      if (fScore[key] < lowestF) {
        lowestF = fScore[key];
        currentKey = key;
      }
    }

    const currentNode = openSet[currentKey];

    // Check if we've reached the destination
    if (currentNode.x === end.x && currentNode.y === end.y) {
      // Reconstruct path
      const path = [currentNode];
      let traceKey = currentKey;
      while (cameFrom[traceKey]) {
        traceKey = cameFrom[traceKey];
        const coords = traceKey.split(',');
        path.push(
          openSet[traceKey] || closedSet[traceKey] || { x: parseInt(coords[0]), y: parseInt(coords[1]) }
        );
      }
      return { path, cost: gScore[currentKey], iterations };
    }

    // Move current node from open to closed
    delete openSet[currentKey];
    closedSet[currentKey] = currentNode;

    // Evaluate neighbors
    const neighbors = getNeighbors(currentNode);
    for (const neighbor of neighbors) {
      const neighborKey = nodeKey(neighbor);

      if (closedSet[neighborKey]) continue;

      const tentativeG = gScore[currentKey] + neighbor.moveCost;

      if (gScore[neighborKey] === undefined || tentativeG < gScore[neighborKey]) {
        cameFrom[neighborKey] = currentKey;
        gScore[neighborKey] = tentativeG;
        fScore[neighborKey] = tentativeG + heuristic(neighbor, end);
        openSet[neighborKey] = neighbor;
      }
    }
  }

  // No path found
  return { path: [], cost: Infinity, iterations };
}

// Run the pathfinder
const result = findPath(startNode, endNode);
console.log('Path length:', result.path.length, 'Cost:', result.cost, 'Iterations:', result.iterations);
```

## Key observations from the deobfuscated code:

1. **Algorithm**: Standard **A\*** with open/closed sets stored as object dictionaries keyed by `"x,y"` strings
2. **Grid**: 20×15 grid with 25% random walls
3. **Movement**: 8-directional — cardinal moves cost `1`, diagonal moves cost `1.414` (≈√2)
4. **Heuristic**: Configurable Manhattan or Euclidean distance
5. **Termination**: Stops when the goal is found or after 1000 iterations
6. **Path reconstruction**: Traces back through a `cameFrom` parent map
